package api

import (
	"bytes"
	"crypto/tls"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"strings"

	"github.com/sandcastle/cli/internal/config"
)

func verbose() bool {
	// Check both VERBOSE and SANDCASTLE_VERBOSE
	v := strings.ToLower(os.Getenv("VERBOSE"))
	if v == "" {
		v = strings.ToLower(os.Getenv("SANDCASTLE_VERBOSE"))
	}
	return v == "1" || v == "true"
}

func logVerbose(format string, args ...any) {
	if verbose() {
		fmt.Fprintf(os.Stderr, "\033[2m"+format+"\033[0m\n", args...)
	}
}

type Client struct {
	BaseURL     string
	Token       string
	ServerAlias string
	HTTPClient  *http.Client
}

func newHTTPClient(insecure bool) *http.Client {
	if insecure {
		return &http.Client{
			Transport: &http.Transport{
				TLSClientConfig: &tls.Config{InsecureSkipVerify: true},
			},
		}
	}
	return &http.Client{}
}

func NewClient() (*Client, error) {
	cfg, err := config.Load()
	if err != nil {
		return nil, err
	}

	// SANDCASTLE_HOST overrides the active server — accepts a server alias or URL.
	if host := os.Getenv("SANDCASTLE_HOST"); host != "" {
		// 1. Alias match
		if srv, ok := cfg.Servers[host]; ok {
			logVerbose("server (SANDCASTLE_HOST alias): %s (%s)", host, srv.URL)
			return &Client{
				BaseURL:     srv.URL,
				Token:       srv.Token,
				ServerAlias: host,
				HTTPClient:  newHTTPClient(srv.Insecure),
			}, nil
		}
		// 2. URL match — reuse stored token for that server
		normalized := strings.TrimRight(host, "/")
		for alias, srv := range cfg.Servers {
			if strings.TrimRight(srv.URL, "/") == normalized {
				logVerbose("server (SANDCASTLE_HOST url): %s (%s)", alias, normalized)
				return &Client{
					BaseURL:     normalized,
					Token:       srv.Token,
					ServerAlias: alias,
					HTTPClient:  newHTTPClient(srv.Insecure),
				}, nil
			}
		}
		// 3. Unknown URL — use without auth
		logVerbose("server (SANDCASTLE_HOST, unauthenticated): %s", normalized)
		return &Client{
			BaseURL:    normalized,
			HTTPClient: newHTTPClient(false),
		}, nil
	}

	srv, err := cfg.CurrentServerConfig()
	if err != nil {
		return nil, err
	}
	logVerbose("server: %s (%s)", cfg.CurrentServer, srv.URL)
	return &Client{
		BaseURL:     srv.URL,
		Token:       srv.Token,
		ServerAlias: cfg.CurrentServer,
		HTTPClient:  newHTTPClient(srv.Insecure),
	}, nil
}

func NewClientWithToken(baseURL, token string, insecure bool) *Client {
	return &Client{
		BaseURL:    baseURL,
		Token:      token,
		HTTPClient: newHTTPClient(insecure),
	}
}

func (c *Client) do(method, path string, body any, result any) error {
	var bodyReader io.Reader
	var reqData []byte
	if body != nil {
		var err error
		reqData, err = json.Marshal(body)
		if err != nil {
			return fmt.Errorf("marshaling request: %w", err)
		}
		bodyReader = bytes.NewReader(reqData)
	}

	logVerbose("→ %s %s%s", method, c.BaseURL, path)
	if len(reqData) > 0 {
		logVerbose("  request: %s", string(reqData))
	}

	req, err := http.NewRequest(method, c.BaseURL+path, bodyReader)
	if err != nil {
		return fmt.Errorf("creating request: %w", err)
	}

	req.Header.Set("Content-Type", "application/json")
	if c.Token != "" {
		req.Header.Set("Authorization", "Bearer "+c.Token)
	}

	resp, err := c.HTTPClient.Do(req)
	if err != nil {
		return fmt.Errorf("request failed: %w", err)
	}
	defer resp.Body.Close()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return fmt.Errorf("reading response: %w", err)
	}

	logVerbose("← %d (%d bytes)", resp.StatusCode, len(respBody))
	if len(respBody) > 0 {
		logVerbose("  response: %s", string(respBody))
	}

	if resp.StatusCode >= 400 {
		var apiErr APIError
		if json.Unmarshal(respBody, &apiErr) == nil && apiErr.Error != "" {
			return fmt.Errorf("API error (%d): %s", resp.StatusCode, apiErr.Error)
		}
		return fmt.Errorf("API error (%d): %s", resp.StatusCode, string(respBody))
	}

	if result != nil {
		if err := json.Unmarshal(respBody, result); err != nil {
			return fmt.Errorf("parsing response: %w", err)
		}
	}
	return nil
}

// doWithStatus is like do but returns the HTTP status code along with the response body.
func (c *Client) doWithStatus(method, path string, body any) (int, []byte, error) {
	var bodyReader io.Reader
	var reqData []byte
	if body != nil {
		var err error
		reqData, err = json.Marshal(body)
		if err != nil {
			return 0, nil, fmt.Errorf("marshaling request: %w", err)
		}
		bodyReader = bytes.NewReader(reqData)
	}

	logVerbose("→ %s %s%s", method, c.BaseURL, path)
	if len(reqData) > 0 {
		logVerbose("  request: %s", string(reqData))
	}

	req, err := http.NewRequest(method, c.BaseURL+path, bodyReader)
	if err != nil {
		return 0, nil, fmt.Errorf("creating request: %w", err)
	}

	req.Header.Set("Content-Type", "application/json")
	if c.Token != "" {
		req.Header.Set("Authorization", "Bearer "+c.Token)
	}

	resp, err := c.HTTPClient.Do(req)
	if err != nil {
		return 0, nil, fmt.Errorf("request failed: %w", err)
	}
	defer resp.Body.Close()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return 0, nil, fmt.Errorf("reading response: %w", err)
	}

	logVerbose("← %d (%d bytes)", resp.StatusCode, len(respBody))
	if len(respBody) > 0 {
		logVerbose("  response: %s", string(respBody))
	}

	return resp.StatusCode, respBody, nil
}

// Device Auth

func (c *Client) RequestDeviceCode(clientName string) (*DeviceCodeResponse, error) {
	var resp DeviceCodeResponse
	err := c.do("POST", "/api/auth/device_code", DeviceCodeRequest{ClientName: clientName}, &resp)
	return &resp, err
}

func (c *Client) PollDeviceToken(deviceCode string) (token string, pending bool, err error) {
	status, body, err := c.doWithStatus("POST", "/api/auth/device_token", DeviceTokenRequest{DeviceCode: deviceCode})
	if err != nil {
		return "", false, err
	}

	switch status {
	case 200:
		var resp DeviceTokenResponse
		if err := json.Unmarshal(body, &resp); err != nil {
			return "", false, fmt.Errorf("parsing response: %w", err)
		}
		return resp.Token, false, nil
	case 428: // Precondition Required — authorization_pending
		return "", true, nil
	default:
		var apiErr APIError
		if json.Unmarshal(body, &apiErr) == nil && apiErr.Error != "" {
			return "", false, fmt.Errorf("%s", apiErr.Error)
		}
		return "", false, fmt.Errorf("unexpected status %d: %s", status, string(body))
	}
}

// Sandboxes

func (c *Client) ListSandboxes() ([]Sandbox, error) {
	var sandboxes []Sandbox
	err := c.do("GET", "/api/sandboxes", nil, &sandboxes)
	return sandboxes, err
}

func (c *Client) GetSandbox(id int) (*Sandbox, error) {
	var s Sandbox
	err := c.do("GET", fmt.Sprintf("/api/sandboxes/%d", id), nil, &s)
	return &s, err
}

package cmd

import (
	"fmt"
	"sort"
	"text/tabwriter"

	"github.com/sandcastle/cli/api"
	"github.com/spf13/cobra"
)

var (
	projectPath         string
	projectImage        string
	projectTailscale    bool
	projectNoVNC        bool
	projectVNCGeometry  string
	projectVNCDepth     int
	projectNoDocker     bool
	projectSMB          bool
	projectSSHStartTmux bool
)

func init() {
	rootCmd.AddCommand(projectCmd)
	projectCmd.AddCommand(projectListCmd)
	projectCmd.AddCommand(projectCreateCmd)
	projectCmd.AddCommand(projectDeleteCmd)

	projectCreateCmd.Flags().StringVar(&projectPath, "path", "", "Project subdir mounted as both $HOME and /persisted")
	projectCreateCmd.Flags().StringVar(&projectImage, "image", "ghcr.io/thieso2/sandcastle-sandbox:latest", "Default container image")
	projectCreateCmd.Flags().BoolVar(&projectTailscale, "tailscale", false, "Enable Tailscale by default")
	projectCreateCmd.Flags().BoolVar(&projectNoVNC, "no-vnc", false, "Disable VNC by default")
	projectCreateCmd.Flags().StringVar(&projectVNCGeometry, "vnc-geometry", "", "Default VNC screen resolution")
	projectCreateCmd.Flags().IntVar(&projectVNCDepth, "vnc-depth", 0, "Default VNC color depth")
	projectCreateCmd.Flags().BoolVar(&projectNoDocker, "no-docker", false, "Disable Docker by default")
	projectCreateCmd.Flags().BoolVar(&projectSMB, "smb", false, "Enable SMB by default")
	projectCreateCmd.Flags().BoolVar(&projectSSHStartTmux, "ssh-start-tmux", true, "Start tmux on SSH login by default")
}

var projectCmd = &cobra.Command{
	Use:   "project",
	Short: "Manage reusable project presets",
}

var projectListCmd = &cobra.Command{
	Use:     "list",
	Aliases: []string{"ls"},
	Short:   "List saved projects",
	RunE: func(cmd *cobra.Command, args []string) error {
		client, err := api.NewClient()
		if err != nil {
			return err
		}

		projects, err := client.ListProjects()
		if err != nil {
			return err
		}
		sort.Slice(projects, func(i, j int) bool { return projects[i].Name < projects[j].Name })

		if len(projects) == 0 {
			fmt.Println("No projects saved.")
			return nil
		}

		w := tabwriter.NewWriter(cmd.OutOrStdout(), 0, 0, 2, ' ', 0)
		fmt.Fprintln(w, "NAME\tPATH\tIMAGE\tSERVICES")
		for _, p := range projects {
			services := []string{}
			if p.DockerEnabled {
				services = append(services, "docker")
			}
			if p.VNCEnabled {
				services = append(services, "vnc")
			}
			if p.Tailscale {
				services = append(services, "tailscale")
			}
			if p.SMBEnabled {
				services = append(services, "smb")
			}
			fmt.Fprintf(w, "%s\t%s\t%s\t%s\n", p.Name, p.Path, p.Image, joinCSV(services))
		}
		return w.Flush()
	},
}

var projectCreateCmd = &cobra.Command{
	Use:   "create <name>",
	Short: "Create a reusable project preset",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		if projectPath == "" {
			return fmt.Errorf("--path is required")
		}

		client, err := api.NewClient()
		if err != nil {
			return err
		}

		project, err := client.CreateProject(api.CreateProjectRequest{
			Name:          args[0],
			Path:          projectPath,
			Image:         projectImage,
			Tailscale:     projectTailscale,
			VNCEnabled:    !projectNoVNC,
			VNCGeometry:   projectVNCGeometry,
			VNCDepth:      projectVNCDepth,
			DockerEnabled: !projectNoDocker,
			SMBEnabled:    projectSMB,
			SSHStartTmux:  projectSSHStartTmux,
		})
		if err != nil {
			return err
		}

		fmt.Printf("Project %q created (%s).\n", project.Name, project.Path)
		return nil
	},
}

var projectDeleteCmd = &cobra.Command{
	Use:   "delete <id>",
	Short: "Delete a project preset",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		id, err := parseID(args[0])
		if err != nil {
			return err
		}

		client, err := api.NewClient()
		if err != nil {
			return err
		}
		return client.DestroyProject(id)
	},
}

func joinCSV(items []string) string {
	if len(items) == 0 {
		return "-"
	}
	out := items[0]
	for i := 1; i < len(items); i++ {
		out += "," + items[i]
	}
	return out
}

func parseID(s string) (int, error) {
	var id int
	_, err := fmt.Sscanf(s, "%d", &id)
	if err != nil {
		return 0, fmt.Errorf("invalid id %q", s)
	}
	return id, nil
}

